syntax.postgresql:
-- Trigger function to auto-update updated_at timestamp
CREATE FUNCTION update_timestamp()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

-- Row-level trigger
CREATE TRIGGER trg_users_updated
  BEFORE UPDATE ON users
  FOR EACH ROW
  EXECUTE FUNCTION update_timestamp();

-- Statement-level trigger for logging bulk operations
CREATE FUNCTION log_bulk_insert()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  INSERT INTO audit_log (table_name, operation, executed_at)
  VALUES (TG_TABLE_NAME, TG_OP, NOW());
  RETURN NULL;
END;
$$;

CREATE TRIGGER trg_orders_bulk_log
  AFTER INSERT ON orders
  FOR EACH STATEMENT
  EXECUTE FUNCTION log_bulk_insert();

syntax.sqlite:
-- BEFORE trigger
CREATE TRIGGER trg_users_before_insert
  BEFORE INSERT ON users
BEGIN
  SELECT RAISE(ABORT, 'Username cannot be empty')
  WHERE NEW.username = '';
END;

-- AFTER trigger
CREATE TRIGGER trg_users_after_delete
  AFTER DELETE ON users
BEGIN
  DELETE FROM orders WHERE user_id = OLD.id;
END;

-- Trigger on INSERT
CREATE TRIGGER trg_on_insert
  AFTER INSERT ON orders
BEGIN
  INSERT INTO notifications (message) VALUES ('New order: ' || NEW.id);
END;

-- Trigger on UPDATE of specific columns
CREATE TRIGGER trg_on_status_change
  AFTER UPDATE OF status ON orders
BEGIN
  INSERT INTO status_history (order_id, old_status, new_status)
  VALUES (OLD.id, OLD.status, NEW.status);
END;

syntax.postgresql:
-- PostgreSQL uses the pg_cron extension for scheduled events
-- Install: CREATE EXTENSION pg_cron;

-- Delete old audit logs every day at midnight
SELECT cron.schedule(
  'cleanup-audit-logs',
  '0 0 * * *',
  $$DELETE FROM audit_log WHERE created_at < NOW() - INTERVAL '90 days'$$
);

-- Refresh materialized view every 5 minutes
SELECT cron.schedule(
  'refresh-order-summary',
  '*/5 * * * *',
  'REFRESH MATERIALIZED VIEW CONCURRENTLY order_summary'
);
